import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { CartService } from '../../core/services/cart.service';
import { OrderService } from '../../core/services/order.service';
import { MoneyPipe } from '../../core/pipes/money.pipe';

@Component({
  selector: 'app-checkout',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink, MoneyPipe],
  templateUrl: './checkout.component.html',
  styleUrl: './checkout.component.css',
})
export class CheckoutComponent {
  readonly items = this.cart.items;
  readonly subtotalCents = this.cart.subtotalCents;
  form: FormGroup;
  placing = false;

  constructor(
    private fb: FormBuilder,
    private cart: CartService,
    private orders: OrderService,
    private router: Router,
  ) {
    this.form = this.fb.group({
      shipName: ['', [Validators.required]],
      shipAddress: ['', [Validators.required]],
    });
  }

  placeOrder(): void {
    if (this.form.invalid || this.items().length === 0) return;
    this.placing = true;
    const { shipName, shipAddress } = this.form.value;
    const order = this.orders.placeOrder(this.items(), shipName, shipAddress);
    this.cart.clear();
    this.router.navigate(['/orders', order.id]);
  }
}
